import React, { useState, useEffect } from 'react';
import { 
  Menu, X, Sun, Moon, Book, FileText, FormInput, Home,
  UserCheck, Gavel, Users, Scale, Building, Briefcase,
  Search, Shield, ClipboardList, HelpCircle, ChevronDown,
  BellDot as BellDotIcon,
  Info as InfoIcon
} from 'lucide-react';

// Import components
import HomePage from './components/HomePage';

const App = () => {
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [currentPage, setCurrentPage] = useState('/');
  const [expandedItems, setExpandedItems] = useState({});

  const toggleExpanded = (path, e) => {
    e.preventDefault();
    setExpandedItems(prev => ({
      ...prev,
      [path]: !prev[path]
    }));
  };

  const navigationItems = [
    { path: '/', icon: Home, label: 'Inicio', spanish: 'Home' },
    { path: '/pleadings', icon: Book, label: 'Pleadings', spanish: 'Pleadings' },
    { path: '/recursos', icon: FileText, label: 'Recursos', spanish: 'Motions',
      subItems: [
        { path: '/recursos/plantillas', label: 'Plantillas', spanish: 'Motion for name correction' },
        { path: '/recursos/guias', label: 'Guías', spanish: 'Video Motion' },
        { path: '/recursos/formularios', label: 'Formularios', spanish: 'Motion' }
      ]
    },
    { path: '/forms', icon: FormInput, label: 'Declaración', spanish: 'Declaration' },
    { 
      path: '/immigration', 
      icon: BellDotIcon, 
      label: 'Immigration', 
      spanish: 'Notices and addresses',
      subItems: [
        { path: '/secretaries', label: 'Secretaries', spanish: 'Secretaries Per Office' },
        { path: '/address', label: 'Address', spanish: 'Address' },
        { path: '/mailout', label: 'Mail-out', spanish: 'Mail-out' }
      ]
    },
    { 
      path: '/criminal', 
      icon: InfoIcon, 
      label: 'Criminal', 
      spanish: 'Basic Information',
      subItems: [
        { path: '/criminal/coversheet', label: 'Defense', spanish: 'Coversheet' },
        { path: '/criminal/i589', label: 'Appeals', spanish: 'i-589 Information' },
        { path: '/criminal/declaration', label: 'Declaration', spanish: 'Declaration Information' }
      ]
    },
    { 
      path: '/family', 
      icon: Users, 
      label: 'Family', 
      spanish: 'Other II',
      subItems: [
        { path: '/family/divorce', label: 'Divorce', spanish: 'Divorce Forms' },
        { path: '/family/custody', label: 'Custody', spanish: 'Custody Documents' }
      ]
    }
  ];

  useEffect(() => {
    const darkModePref = window.matchMedia('(prefers-color-scheme: dark)').matches;
    const savedDarkMode = localStorage.getItem('darkMode');
    const shouldBeDark = savedDarkMode !== null ? savedDarkMode === 'true' : darkModePref;
    setIsDarkMode(shouldBeDark);
    if (shouldBeDark) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, []);

  const toggleDarkMode = () => {
    setIsDarkMode(!isDarkMode);
    document.documentElement.classList.toggle('dark');
    localStorage.setItem('darkMode', (!isDarkMode).toString());
  };

  const handleNavigation = (path) => {
    setCurrentPage(path);
    if (window.innerWidth < 1024) {
      setIsSidebarOpen(false);
    }
  };

  const NavItem = ({ item }) => {
    const hasSubItems = item.subItems && item.subItems.length > 0;
    const isExpanded = expandedItems[item.path];

    return (
      <div key={item.path}>
        <div className="flex flex-col">
          <div
            className={`
              flex items-center justify-between p-3 rounded-lg cursor-pointer
              transition-colors duration-200
              ${currentPage === item.path 
                ? 'bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400' 
                : 'text-gray-700 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-700'}
            `}
            onClick={(e) => hasSubItems ? toggleExpanded(item.path, e) : handleNavigation(item.path)}
          >
            <div className="flex items-center space-x-3 flex-grow">
              <item.icon className="h-5 w-5" />
              <span>{item.spanish}</span>
            </div>
            {hasSubItems && (
              <ChevronDown 
                className={`h-5 w-5 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`}
              />
            )}
          </div>

          {hasSubItems && isExpanded && (
            <div className="ml-6 mt-1 space-y-1">
              {item.subItems.map((subItem) => (
                <div
                  key={subItem.path}
                  onClick={() => handleNavigation(subItem.path)}
                  className={`
                    block px-3 py-2 rounded-md text-sm cursor-pointer
                    transition-colors duration-200
                    ${currentPage === subItem.path
                      ? 'bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400'
                      : 'text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700'}
                  `}
                >
                  {subItem.spanish}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderContent = () => {
    switch(currentPage) {
      case '/':
        return <HomePage onNavigate={handleNavigation} />;
      // Aquí agregaremos los otros componentes cuando los creemos
      default:
        return <div className="text-center">Página en construcción</div>;
    }
  };

  return (
    <div className="min-h-screen bg-white dark:bg-gray-900 transition-colors duration-200">
      {/* Overlay for mobile */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-50 z-20 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Mobile menu button */}
      <button 
        className="fixed top-4 left-4 z-30 lg:hidden p-2 rounded-md bg-white dark:bg-gray-800 shadow-md hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors duration-200"
        onClick={() => setIsSidebarOpen(!isSidebarOpen)}
      >
        {isSidebarOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
      </button>

      {/* Sidebar */}
      <aside className={`
        fixed top-0 left-0 z-20 h-full w-64 
        bg-white dark:bg-gray-800 
        shadow-lg overflow-y-auto
        transition-transform duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        lg:translate-x-0
      `}>
        <div className="flex items-center justify-between p-4 border-b border-gray-200 dark:border-gray-700">
          <h1 className="text-xl font-bold text-gray-900 dark:text-white">Wiki Paralegal</h1>
          <button 
            onClick={toggleDarkMode}
            className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors duration-200"
            aria-label="Toggle dark mode"
          >
            {isDarkMode ? 
              <Sun className="h-5 w-5 text-gray-500 dark:text-gray-400" /> : 
              <Moon className="h-5 w-5 text-gray-500 dark:text-gray-400" />
            }
          </button>
        </div>

        <nav className="p-4 space-y-2">
          {navigationItems.map((item) => (
            <NavItem key={item.path} item={item} />
          ))}
        </nav>
      </aside>

      {/* Main content */}
      <main className={`
        transition-all duration-300 ease-in-out
        ${isSidebarOpen ? 'lg:ml-64' : 'lg:ml-0'}
        p-4 lg:p-8
      `}>
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;
